var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"얘들아! 이쪽이야!","JPN":"みんな！　こっちだよ！","ENG":"Guys! It's this way!","TWN":"各位，這邊！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"크게 다친 데는 없는 것 같네. 무사해서 다행이야!","JPN":"大きいケガはしてないようだね、無事でよかった！","ENG":"You guys don't look too bad. I'm glad you're okay!","TWN":"大家好像都沒受什麼重傷呢，真是太好了！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"중화기...... 싫어...... 벙커 버스터...... 싫어......","JPN":"重火器……イヤだ……、バンカーバスター……だいきらい……","ENG":"Heavy firearms... I don't like it... Bunker buster... I hate it...","TWN":"討厭……重型武器……討厭……掩體炸彈……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"전차 한 대가 하늘로 쾅...... 전차 두 대가 하늘로 쾅...... 전차 세 대가......","JPN":"戦車1台が空を飛んでドカン……戦車2台が空を飛んでドカン……戦車3台が……","ENG":"One tank goes BOOM... Two tanks go BOOM... Three tanks go...","TWN":"一台戰車飛到天空爆炸……兩台戰車飛到天空爆炸……三台戰車……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 아가씨. 저 친구들 괜찮은 건가?","JPN":"おい、嬢ちゃん。あの子たち、大丈夫なのか？","ENG":"Hey, miss? Are they okay?","TWN":"喂，小姐，那幾位朋友沒事吧？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무리 봐도 PTSD 초기 증상으로 보이는데......?","JPN":"どう見てもPTSDの初期症状に見えるが……？","ENG":"That looks like the early signs of PTSD...","TWN":"那個樣子不管怎麼看，都像是創傷後遺症的初期症狀啊？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음...... 그 용병 녀석들이 못살게 굴었던 거겠지. 그거 말고 뭐가 있겠어?","JPN":"……あの傭兵野郎どもに散々苦労させられたんだよ。それしかない。","ENG":"Umm... Those mercenary jerks must have given them a hard time... What else could it be?","TWN":"嗯……應該是被那群傭兵折磨的吧，不然呢？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그런가? 그런데 왜 자꾸 이쪽을 원망스럽게 쳐다보고 있는 건지 모르겠군.","JPN":"……そうか？　でも、なんでこっちを恨めしそうに見つめているんだろうな。","ENG":"I guess so... But why does she keep glaring at me?","TWN":"……是嗎？但為什麼她們一直哀怨地瞪著這邊……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 글쎄......? 그건 나도 잘......","JPN":"さ、さあ……？　私にもよくわから……","ENG":"Err... I'm not sure...","TWN":"誰、誰知道呢？我也不太清……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"미, 미나 씨!","JPN":"ミ、ミナさん！","ENG":"M-Mina!","TWN":"米、米娜小姐！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으, 으익?!","JPN":"う、うえっ！？","ENG":"Huh?!","TWN":"嗚哇！？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"여기 계셨군요, 미나 씨! 정말 감사드려요!","JPN":"ここにいらしたのですね！　ミナさん、本当にありがとう！","ENG":"I was looking for you, Mina! Thank you so much!","TWN":"妳在這裡呀，米娜小姐！真的是太謝謝妳了！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으, 응......? 가, 감사?","JPN":"う、うん……？　か、感謝？","ENG":"Uh... Thank you?","TWN":"咦……？謝、謝謝我？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"네! 미나 씨가 저를 믿어주신 덕분에 해낼 수 있었어요.","JPN":"はい！　ミナさんが私を信じてくれたおかげで、ここまでできました。","ENG":"Yes! I was able to do it because you trusted me!","TWN":"嗯！多虧米娜小姐相信我，我成功了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"제 소심한 성격은 영원히 고칠 수 없다고 생각했었는데, 덕분에 자신감이 생긴 것 같아요.","JPN":"私の臆病な性格はいつまでも直せないと思ってましたが、おかげさまで自信がついたみたいです。","ENG":"I never thought I'd ever break out of my shy bubble... But I'm bursting with confidence thanks to you!","TWN":"我原本以為我永遠無法改掉自己膽怯的性格。但多虧了米娜小姐，我好像變得有自信了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"앞으로도 훌륭한 인간 벙커 버스터가 되기 위해 힘낼 테니까, 지켜봐 주세요!","JPN":"これからも、立派な人間バンカーバスターになるためにがんばりますので、見守ってくださいね！","ENG":"I'll do my best to become the best Human Bunker Buster in the world! I won't let you down!","TWN":"我以後也會為了成為更優秀的人類掩體炸彈努力的，請米娜小姐拭目以待吧！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아...... 그, 그래. 행운을 빌게......","JPN":"あ……そ、そう……幸運を祈るよ……","ENG":"Oh... Sure... Good luck...","TWN":"喔，這、這樣喔，那祝妳好運……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 혹시라도 다른 사람이 물어보면 내가 도와줬다는 이야기는 하지 말아 줘......","JPN":"それともし他人に聞かれたら、私が助けたという話はしないでね……","ENG":"But if anyone asks, don't tell them I helped you...","TWN":"然後，如果有人問起這件事，千萬別說是我幫妳的……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"역시! 미나 씨는 너무 겸손하신 것 같아요!!","JPN":"さすが！　ミナさんはなんて謙虚な方なんでしょう！！","ENG":"Wow! You're so humble!","TWN":"真不愧是米娜小姐！真是太謙虛了！！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"하지만...... 그래서는 신세 진 제가 너무 미안해서......","JPN":"でも……せっかく助けて頂いたのに、申し訳ないというか……","ENG":"But... I can't do that and take all the credit...","TWN":"但是……這麼受到米娜小姐的照顧，我實在太不好意思……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아냐. 괜찮아. 정말 괜찮으니까......","JPN":"いや、大丈夫。本当に大丈夫だから……","ENG":"No. It's okay. It's really okay!","TWN":"不、不要緊，真的不要緊……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이건 우리 둘만의 작은 비밀로 간직하는 거야.","JPN":"これは私たち2人だけの秘密にしよう。","ENG":"Let's just say it's our little secret.","TWN":"就把這個當作我們之間的小秘密吧。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......알겠지?","JPN":"……ねっ？","ENG":"Okay?","TWN":"……知道了嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"네. 미나 씨가 꼭 그러고 싶으시다면요...... 알겠습니다!","JPN":"はい、それがミナさんの希望でしたら……わかりました！","ENG":"Sure. If you say so... Okay!","TWN":"好的，如果米娜小姐希望這樣的話……我明白了！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 이야기는 끝났나?","JPN":"おい、話は済んだか？","ENG":"Hey, are you done talking?","TWN":"喂，你們聊完了吧？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"놈들이 들이닥치기 전에 빨리 가자고.","JPN":"奴らが押し寄せてくる前に早く行こう。","ENG":"Let's hurry up and go before they arrive.","TWN":"我們得在敵人過來之前趕快出發才行。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 앞으로 조금만 가면 침식 억제기가 있는 곳이다.","JPN":"この先にもう少し進めば、侵食抑制装置がある。","ENG":"The Inhibitor isn't far now.","TWN":"再往前走一點，就能到達侵蝕抑制器的所在地了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};